  1	import * as React from 'react';
  2	import { getName } from '@odf/shared';
  3	import { TableSkeletonLoader } from '@odf/shared/skeletal-loader/TableSkeleton';
  4	import {
  5	  K8sResourceCommon,
  6	  ListPageFilter,
  7	  useListPageFilter,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import * as _ from 'lodash-es';
 10	import { Thead, Tr, Th, Tbody, Table } from '@patternfly/react-table';
 11	
 12	export type SelectedResources = {
 13	  storageClass: {
 14	    [name: string]: boolean;
 15	  };
 16	  volumeSnapshotClass: {
 17	    [name: string]: boolean;
 18	  };
 19	};
 20	
 21	export type ResourceDistributionTableProps = {
 22	  resources: K8sResourceCommon[];
 23	  selectedResources: SelectedResources;
 24	  setSelectedResources: React.Dispatch<React.SetStateAction<SelectedResources>>;
 25	  RowGenerator: React.FC<RowGeneratorProps<K8sResourceCommon>>;
 26	  columns: string[];
 27	  loaded: boolean;
 28	  resourceType: 'storageClass' | 'volumeSnapshotClass';
 29	};
 30	
 31	export type RowGeneratorProps<T extends K8sResourceCommon> = {
 32	  resource: T;
 33	  onSelect: (selected: boolean) => void;
 34	  isSelected: boolean;
 35	  rowIndex: number;
 36	};
 37	
 38	export const ResourceDistributionTable: React.FC<
 39	  ResourceDistributionTableProps
 40	> = ({
 41	  resources,
 42	  RowGenerator,
 43	  selectedResources,
 44	  setSelectedResources,
 45	  loaded,
 46	  columns,
 47	  resourceType,
 48	}) => {
 49	  const [areAllResourcesSelected, setAllResourcesSelected] =
 50	    React.useState(false);
 51	
 52	  React.useEffect(() => {
 53	    const allSelected = _.isEmpty(resources)
 54	      ? false
 55	      : resources.every((resource) => {
 56	          const name = getName(resource);
 57	          return !!selectedResources?.[resourceType]?.[name];
 58	        });
 59	    if (allSelected) {
 60	      setAllResourcesSelected(true);
 61	    }
 62	  }, [resourceType, resources, selectedResources]);
 63	  const onSelectRow = React.useCallback(
 64	    (resource: K8sResourceCommon) => (selected: boolean) => {
 65	      const updatedResources = {
 66	        ...selectedResources,
 67	      };
 68	      updatedResources[resourceType][getName(resource)] = selected;
 69	      const isAllSelected = Object.entries(
 70	        updatedResources?.[resourceType]
 71	      ).every(([, v]) => v);
 72	      if (isAllSelected) {
 73	        setAllResourcesSelected(true);
 74	      } else {
 75	        setAllResourcesSelected(false);
 76	      }
 77	      setSelectedResources(updatedResources);
 78	    },
 79	    [resourceType, selectedResources, setSelectedResources]
 80	  );
 81	
 82	  const isRowSelected = React.useCallback(
 83	    (resource: K8sResourceCommon) =>
 84	      selectedResources[resourceType]?.[getName(resource)],
 85	    [resourceType, selectedResources]
 86	  );
 87	
 88	  const [unfilteredData, filteredData, onFilterChange] =
 89	    useListPageFilter(resources);
 90	
 91	  const selectAllResources = (select: boolean) => {
 92	    setAllResourcesSelected(select);
 93	    const newSelectedResources = {
 94	      [resourceType]: filteredData.reduce((acc, storageClass) => {
 95	        acc[storageClass.metadata.name] = select;
 96	        return acc;
 97	      }, {}),
 98	    };
 99	    setSelectedResources((prev) => ({ ...prev, ...newSelectedResources }));
100	  };
101	  return !loaded ? (
102	    <TableSkeletonLoader columns={4} rows={8} />
103	  ) : (
104	    <>
105	      <ListPageFilter
106	        data={unfilteredData}
107	        loaded={loaded}
108	        onFilterChange={onFilterChange}
109	        hideColumnManagement={true}
110	      />
111	      <Table variant="compact" data-test-id="resource-distribution-table">
112	        <Thead>
113	          <Tr>
114	            <Th
115	              select={{
116	                onSelect: (_event, isSelecting) =>
117	                  selectAllResources(isSelecting),
118	                isSelected: areAllResourcesSelected,
119	              }}
120	            />
121	            {columns.map((columnName) => (
122	              <Th key={columnName}>{columnName}</Th>
123	            ))}
124	          </Tr>
125	        </Thead>
126	        <Tbody>
127	          {filteredData.map((resource, index) => (
128	            <RowGenerator
129	              key={resource.metadata.uid}
130	              resource={resource}
131	              rowIndex={index}
132	              onSelect={onSelectRow(resource)}
133	              isSelected={isRowSelected(resource)}
134	            />
135	          ))}
136	        </Tbody>
137	      </Table>
138	    </>
139	  );
140	};

