  1	import * as React from 'react';
  2	import { render, screen } from '@testing-library/react';
  3	import '@testing-library/jest-dom';
  4	import userEvent from '@testing-library/user-event';
  5	import { StorageClassRowGenerator } from '../../modals/ResourceDistributionModal/ResourceDistributionModal';
  6	import {
  7	  ResourceDistributionTable,
  8	  SelectedResources,
  9	} from './ResourceDistributionTable';
 10	
 11	const resources = [
 12	  {
 13	    apiVersion: 'v1',
 14	    kind: 'StorageClass',
 15	    metadata: {
 16	      name: 'test-storage-class',
 17	      namespace: 'test-namespace',
 18	    },
 19	    provisioner: 'test-provisioner',
 20	  },
 21	  {
 22	    apiVersion: 'v1',
 23	    kind: 'VolumeSnapshotClass',
 24	    metadata: {
 25	      name: 'test-snapshot-class',
 26	      namespace: 'test-namespace',
 27	    },
 28	    driver: 'test-driver',
 29	  },
 30	];
 31	
 32	const selectedResources: SelectedResources = {
 33	  storageClass: {
 34	    'test-storage-class': false,
 35	  },
 36	  volumeSnapshotClass: {
 37	    'test-snapshot-class': false,
 38	  },
 39	};
 40	
 41	jest.mock('@openshift-console/dynamic-plugin-sdk', () => {
 42	  return {
 43	    ...jest.requireActual('@openshift-console/dynamic-plugin-sdk'),
 44	    useListPageFilter: jest.fn().mockReturnValue([
 45	      [],
 46	      [
 47	        {
 48	          apiVersion: 'v1',
 49	          kind: 'StorageClass',
 50	          metadata: {
 51	            name: 'test-storage-class',
 52	            namespace: 'test-namespace',
 53	          },
 54	          provisioner: 'test-provisioner',
 55	        },
 56	      ],
 57	      jest.fn(),
 58	    ]),
 59	  };
 60	});
 61	
 62	describe('Resource distribution table component renders correctly for a storage class', () => {
 63	  it('Renders basic features correctly', () => {
 64	    render(
 65	      <ResourceDistributionTable
 66	        columns={['Name', 'Provisioner', 'Deletion policy']}
 67	        loaded={true}
 68	        selectedResources={selectedResources}
 69	        setSelectedResources={jest.fn()}
 70	        resources={resources}
 71	        RowGenerator={StorageClassRowGenerator as any}
 72	        resourceType={'storageClass'}
 73	      />
 74	    );
 75	    expect(
 76	      screen.getByTestId('resource-distribution-table')
 77	    ).toBeInTheDocument();
 78	
 79	    expect(screen.getByText('Name')).toBeInTheDocument();
 80	    expect(screen.getByText('Provisioner')).toBeInTheDocument();
 81	    expect(screen.getByText('Deletion policy')).toBeInTheDocument();
 82	    expect(screen.getByText('test-storage-class')).toBeInTheDocument();
 83	  });
 84	  it('Selection invokes setSelectedResources with correct parameters', async () => {
 85	    const setSelectedResourcesMock = jest.fn();
 86	    render(
 87	      <ResourceDistributionTable
 88	        columns={['Name', 'Provisioner', 'Deletion policy']}
 89	        loaded={true}
 90	        selectedResources={selectedResources}
 91	        setSelectedResources={setSelectedResourcesMock}
 92	        resources={resources}
 93	        RowGenerator={StorageClassRowGenerator as any}
 94	        resourceType={'storageClass'}
 95	      />
 96	    );
 97	    const checkbox = screen.getByLabelText('Select row 0');
 98	    expect(checkbox).toBeInTheDocument();
 99	    const user = userEvent.setup();
100	    await user.click(checkbox);
101	    expect(setSelectedResourcesMock).toHaveBeenCalledWith({
102	      volumeSnapshotClass: {
103	        'test-snapshot-class': false,
104	      },
105	      storageClass: {
106	        'test-storage-class': true,
107	      },
108	    });
109	    // Test select all
110	    const selectAll = screen.getByLabelText('Select all rows');
111	    expect(selectAll).toBeInTheDocument();
112	    await userEvent.click(selectAll);
113	    expect(setSelectedResourcesMock).toHaveBeenCalledWith({
114	      volumeSnapshotClass: {
115	        'test-snapshot-class': false,
116	      },
117	      storageClass: {
118	        'test-storage-class': true,
119	      },
120	    });
121	  });
122	});

